package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    private lateinit var sharedContentView: TextView
    private lateinit var sharedImageView: ImageView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_receiver)

        sharedContentView = findViewById(R.id.sharedContentView)
        sharedImageView = findViewById(R.id.sharedImageView)

        when (intent.action) {
            Intent.ACTION_SEND -> {
                handleSendIntent(intent)
            }
            // Uncomment and implement handleSendMultipleIntents if you also want to support sharing multiple items
            // Intent.ACTION_SEND_MULTIPLE -> {
            //     handleSendMultipleIntents(intent)
            // }
        }
    }

    private fun handleSendIntent(intent: Intent) {
        when (intent.type) {
            "text/plain" -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                if (!sharedText.isNullOrBlank()) {
                    sharedContentView.text = "Shared Text/URL:\n$sharedText"
                    sharedImageView.setImageDrawable(null) // Clear any previous image
                    sharedImageView.visibility = android.view.View.GONE
                    sharedContentView.visibility = android.view.View.VISIBLE
                } else {
                    sharedContentView.text = "No text content found in share."
                    sharedImageView.setImageDrawable(null)
                    sharedImageView.visibility = android.view.View.GONE
                    sharedContentView.visibility = android.view.View.VISIBLE
                }
            }
            in listOf("image/jpeg", "image/png", "image/gif", "image/webp", "image/*") -> {
                val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                if (imageUri != null) {
                    try {
                        sharedImageView.setImageURI(imageUri)
                        sharedContentView.text = "Shared Image URI:\n$imageUri"
                        sharedImageView.visibility = android.view.View.VISIBLE
                        sharedContentView.visibility = android.view.View.VISIBLE // Keep URI text visible
                    } catch (e: Exception) {
                        sharedContentView.text = "Error loading image: ${e.message}\nURI: $imageUri"
                        sharedImageView.setImageDrawable(null)
                        sharedImageView.visibility = android.view.View.GONE
                        sharedContentView.visibility = android.view.View.VISIBLE
                    }
                } else {
                    sharedContentView.text = "No image URI found in share."
                    sharedImageView.setImageDrawable(null)
                    sharedImageView.visibility = android.view.View.GONE
                    sharedContentView.visibility = android.view.View.VISIBLE
                }
            }
            else -> {
                sharedContentView.text = "Unsupported content type: ${intent.type}"
                sharedImageView.setImageDrawable(null)
                sharedImageView.visibility = android.view.View.GONE
                sharedContentView.visibility = android.view.View.VISIBLE
            }
        }
    }

